import{_ as a,o,c as i,ai as s}from"./chunks/framework.CsYGeNYI.js";const b=JSON.parse('{"title":"Peekaboo Bridge","description":"","frontmatter":{"read_when":["在 OpenSoul.app 中托管 PeekabooBridge","通过 Swift Package Manager 集成 Peekaboo","更改 PeekabooBridge 协议/路径"],"summary":"用于 macOS UI 自动化的 PeekabooBridge 集成","title":"Peekaboo Bridge","x-i18n":{"generated_at":"2026-02-01T21:32:57Z","model":"claude-opus-4-5","provider":"pi","source_hash":"b5b9ddb9a7c59e153a1d5d23c33616bb1542b5c7dadedc3af340aeee9ba03487","source_path":"platforms/mac/peekaboo.md","workflow":15}},"headers":[],"relativePath":"zh-CN/platforms/mac/peekaboo.md","filePath":"zh-CN/platforms/mac/peekaboo.md","lastUpdated":1771906665000}'),r={name:"zh-CN/platforms/mac/peekaboo.md"};function d(p,e,l,t,n,c){return o(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="peekaboo-bridge-macos-ui-自动化" tabindex="-1"><a class="header-anchor" href="#peekaboo-bridge-macos-ui-自动化">#</a> Peekaboo Bridge（macOS UI 自动化）</h1><p>OpenSoul 可以将 <strong>PeekabooBridge</strong> 作为本地的、权限感知的 UI 自动化代理进行托管。这使得 <code>peekaboo</code> CLI 能够驱动 UI 自动化，同时复用 macOS 应用的 TCC 权限。</p><h2 id="这是什么-以及不是什么" tabindex="-1"><a class="header-anchor" href="#这是什么-以及不是什么">#</a> 这是什么（以及不是什么）</h2><ul><li><strong>宿主</strong>：OpenSoul.app 可以作为 PeekabooBridge 宿主。</li><li><strong>客户端</strong>：使用 <code>peekaboo</code> CLI（无需单独的 <code>opensoul ui ...</code> 界面）。</li><li><strong>界面</strong>：视觉叠加层保留在 Peekaboo.app 中；OpenSoul 只是一个轻量代理宿主。</li></ul><h2 id="启用桥接" tabindex="-1"><a class="header-anchor" href="#启用桥接">#</a> 启用桥接</h2><p>在 macOS 应用中：</p><ul><li>设置 → <strong>启用 Peekaboo Bridge</strong></li></ul><p>启用后，OpenSoul 会启动一个本地 UNIX 套接字服务器。如果禁用，宿主会停止，<code>peekaboo</code> 将回退到其他可用宿主。</p><h2 id="客户端发现顺序" tabindex="-1"><a class="header-anchor" href="#客户端发现顺序">#</a> 客户端发现顺序</h2><p>Peekaboo 客户端通常按以下顺序尝试宿主：</p><ol><li>Peekaboo.app（完整用户体验）</li><li>Claude.app（如已安装）</li><li>OpenSoul.app（轻量代理）</li></ol><p>使用 <code>peekaboo bridge status --verbose</code> 查看当前活跃的宿主及使用的套接字路径。你可以通过以下方式覆盖：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> PEEKABOO_BRIDGE_SOCKET</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/path/to/bridge.sock</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="安全与权限" tabindex="-1"><a class="header-anchor" href="#安全与权限">#</a> 安全与权限</h2><ul><li>桥接会验证<strong>调用方的代码签名</strong>；强制执行 TeamID 白名单（Peekaboo 宿主 TeamID + OpenSoul 应用 TeamID）。</li><li>请求在约 10 秒后超时。</li><li>如果缺少所需权限，桥接会返回清晰的错误信息，而不是启动系统设置。</li></ul><h2 id="快照行为-自动化" tabindex="-1"><a class="header-anchor" href="#快照行为-自动化">#</a> 快照行为（自动化）</h2><p>快照存储在内存中，并在短暂窗口期后自动过期。如果需要更长的保留时间，请从客户端重新捕获。</p><h2 id="故障排除" tabindex="-1"><a class="header-anchor" href="#故障排除">#</a> 故障排除</h2><ul><li>如果 <code>peekaboo</code> 报告&quot;bridge client is not authorized&quot;，请确保客户端已正确签名，或仅在<strong>调试</strong>模式下使用 <code>PEEKABOO_ALLOW_UNSIGNED_SOCKET_CLIENTS=1</code> 运行宿主。</li><li>如果未找到宿主，请打开其中一个宿主应用（Peekaboo.app 或 OpenSoul.app）并确认已授予权限。</li></ul>',19)])])}const k=a(r,[["render",d]]);export{b as __pageData,k as default};
